import{_ as e,o as r,c as t,ae as n}from"./chunks/framework.Cuy5ADyd.js";const d=JSON.parse('{"title":"加入我们","description":"","frontmatter":{},"headers":[],"relativePath":"zh-Hans/join.md","filePath":"zh-Hans/join.md"}'),o={name:"zh-Hans/join.md"};function s(i,a,p,l,m,_){return r(),t("div",null,[...a[0]||(a[0]=[n('<h1 id="加入我们" tabindex="-1">加入我们 <a class="header-anchor" href="#加入我们" aria-label="Permalink to &quot;加入我们&quot;">​</a></h1><p>一直有许多伙伴想成为我们的一员，却苦于不知道如何展现自己的才能和热情。2025年10月5日，我们召开了第三届年会，在章程的 8.05 节加入了「新成员招募项目」（New Member Recruitment Programs, NMRP）的具体说明，希望能解决这个问题，让以后的大家可以通过 NMRP 的流程来加入我们。</p><p>在这个页面，我们会发布最新的 NMRP 项目信息。除此之外，也可以通过社交媒体或者电子邮件联系我们。</p><p>请注意，通过 NMRP 加入的成员并不会获得任何财务报酬。一般来说，成为我们的成员（member）和被我们雇佣是互斥的。当然，作为一个小组织，我们截至2025年10月31日还<strong>没有任何付薪受雇员工</strong>。我们的组员、组长和理事们（包括执行理事即理事长在内）都是无薪志愿成员。将来如果我们会有带薪资的岗位，也不会这样去称呼。</p><h2 id="进行中的-nmrp-项目" tabindex="-1">进行中的 NMRP 项目 <a class="header-anchor" href="#进行中的-nmrp-项目" aria-label="Permalink to &quot;进行中的 NMRP 项目&quot;">​</a></h2><p>还没有。</p><h2 id="过去的-nmrp-项目" tabindex="-1">过去的 NMRP 项目 <a class="header-anchor" href="#过去的-nmrp-项目" aria-label="Permalink to &quot;过去的 NMRP 项目&quot;">​</a></h2><p>也还没有。</p>',8)])])}const h=e(o,[["render",s]]);export{d as __pageData,h as default};
